import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import "./Notes.css";

export default function Notes() {
  const [notes, setNotes] = useState([]);

  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem("myNotes")) || [];
    setNotes(saved);
  }, []);

  function saveNote(e) {
    e.preventDefault();
    const title = e.target.title.value.trim();
    const content = e.target.content.value.trim();

    if (!title || !content) {
      alert("Please fill in both fields.");
      return;
    }

    const newNote = { title, content };
    const updatedNotes = [newNote, ...notes];
    setNotes(updatedNotes);
    localStorage.setItem("myNotes", JSON.stringify(updatedNotes));

    e.target.title.value = "";
    e.target.content.value = "";
  }

  return (
    <div className="notes-container">
      <h1>My Notes</h1>
      <form onSubmit={saveNote}>
        <label>Title</label>
        <input name="title" placeholder="Title" />

        <label>Content</label>
        <textarea name="content" placeholder="Write your note here..." />

        <button type="submit">Save Note</button>
      </form>

      {notes.length === 0 ? (
        <p>No notes yet.</p>
      ) : (
        notes.map((n, i) => (
          <div key={i} className="note">
            <h3>{n.title}</h3>
            <p>{n.content}</p>
          </div>
        ))
      )}

      <h2>
        📚 Study Resources to Learn and Revise
      </h2>

      <div className="resources">
        <div className="resource">
          <img src="https://www.w3schools.com/images/w3schools_green.jpg" alt="W3Schools" />
          <h4>🌐 W3Schools</h4>
          <p>Learn HTML, CSS, JavaScript, and more with simple tutorials.</p>
          <a href="https://www.w3schools.com/" target="_blank" rel="noreferrer">Visit</a>
        </div>

        <div className="resource">
          <img src="https://media.geeksforgeeks.org/wp-content/uploads/20230822114333/gfg-new-logo.png" alt="GeeksforGeeks" />
          <h4>📚 GeeksforGeeks</h4>
          <p>Master programming concepts, algorithms, and coding questions.</p>
          <a href="https://www.geeksforgeeks.org/" target="_blank" rel="noreferrer">Visit</a>
        </div>

        <div className="resource">
          <img src="https://design-style-guide.freecodecamp.org/downloads/freeCodeCamp.png" alt="freeCodeCamp" />
          <h4>⚡ freeCodeCamp</h4>
          <p>Learn coding by building projects with free full-length courses.</p>
          <a href="https://www.freecodecamp.org/" target="_blank" rel="noreferrer">Visit</a>
        </div>

        <div className="resource">
          <img src="https://developer.mozilla.org/static/img/favicon144.png" alt="MDN Web Docs" />
          <h4>📖 MDN Web Docs</h4>
          <p>The best official docs for web technologies like HTML, CSS, JS.</p>
          <a href="https://developer.mozilla.org/" target="_blank" rel="noreferrer">Visit</a>
        </div>

        <div className="resource">
          <img src="https://static.javatpoint.com/images/logo/jtp-logo.png" alt="JavaTpoint" />
          <h4>📗 JavaTpoint</h4>
          <p>Simple explanations for Java, Python, C, C++, Web Dev topics.</p>
          <a href="https://www.javatpoint.com/" target="_blank" rel="noreferrer">Visit</a>
        </div>

        <div className="resource">
          <img src="https://www.programiz.com/sites/tutorial2program/files/cover-programiz.png" alt="Programiz" />
          <h4>📘 Programiz</h4>
          <p>Easy tutorials and examples for Python, C, C++, Java beginners.</p>
          <a href="https://www.programiz.com/" target="_blank" rel="noreferrer">Visit</a>
        </div>
      </div>

      <p>
        <Link to="/dashboard">⇐ Back to Dashboard</Link>
      </p>
    </div>
  );
}
